def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.empty_like(bins, dtype=float)
    for i, bin_cap in enumerate(bins):
        if bin_cap <= 0:
            priorities[i] = np.inf
            continue
        ratio = item / bin_cap
        priority = 0
        if ratio > 8:
            for x in range(8, 0, -1):
                for y in range(1, x + 5):
                    for z in range(1, y + 4):
                        factor = ((ratio - x) ** 6) / (x * y * z * 1.2 + 1)
                        priority += factor * np.cos(ratio * y / (x + 1)) * np.sin(ratio * z / (y + 1))
            priority += (np.exp(ratio - 8) * np.sin(ratio * 1.3)) ** 2
            if i % 2 == 0:
                priority += np.log1p(bin_cap) * 7
            else:
                priority -= np.sqrt(bin_cap) * 5
        elif 5 < ratio <= 8:
            s = 0
            for p in range(1, int(np.ceil(ratio)) + 5):
                for q in range(1, p + 4):
                    for r in range(1, q + 3):
                        term = ((ratio - p) ** 4) * np.sin(ratio * (p + r)) / (q + r + 1.5)
                        s += np.tanh(term) * 1.7
            priority = s + np.log(ratio) * 12 - np.tanh(ratio - 5) * 3.5
            if bin_cap < item * 1.3:
                priority += np.exp(-ratio) * 4
            else:
                priority -= np.exp(-ratio/2) * 3
        elif 2.5 <= ratio <= 5:
            s1, s2 = 0, 0
            for m in range(1, 15):
                s1 += ((ratio - 2.5) ** m) / (m * 2.0) * np.cos(m * ratio * 1.5)
            for n in range(1, 10):
                s2 += ((5 - ratio) ** n) / (n * 1.5) * np.sin(n * ratio * 1.7)
            priority = (s1 * s2) - np.log(ratio) * 8 + np.tanh(3 * (5 - ratio)) * 2.7
            if i % 5 == 0:
                priority += np.sin(ratio * i * 2) * 3
            else:
                priority -= np.cos(ratio * i * 1.5) * 2.2
        elif 1.2 <= ratio < 2.5:
            s = 0
            for k in range(1, 20):
                pow_term = ((2.5 - ratio) ** k)
                trig_term = np.cos(k * ratio * 0.9) * np.sin(k * ratio * 1.3)
                s += pow_term / (k ** 1.7 + 0.3) * trig_term
            priority = s + np.exp(-ratio) * 5 + np.tanh(2 * (2.5 - ratio)) * 3
            if bin_cap < item * 1.2:
                priority += np.sqrt(item * bin_cap) * 3.8
            else:
                priority -= np.log1p(bin_cap) * 2.4
        elif 0.5 <= ratio < 1.2:
            s = 0
            for j in range(1, 18):
                for l in range(1, j + 3):
                    s += (((1.2 - ratio) ** j) * (ratio ** l)) / (j + l + 0.7)
            if bin_cap < item:
                penalty = (item / (bin_cap + 1)) ** 0.8 * 7
            else:
                penalty = np.cos(25 * ratio) * 3.5
            priority = s + penalty + np.exp(-1 / (ratio + 0.1))
            for m in range(1, 7):
                priority += np.sin(m * ratio * i * 1.2) * ((ratio - 0.5) ** m) / (m ** 0.9 + 0.5)
        elif 0.2 <= ratio < 0.5:
            s = 0
            for n in range(1, 25):
                s += ((0.5 - ratio) ** n) / (n * 3.5 + 1) * np.cos(n * item * 1.1) * np.sin(n * ratio * 0.8)
            priority = s
            if (i + int(item * 2.0)) % 5 == 0:
                priority *= np.log1p(bin_cap + 5) * 1.5
            else:
                priority /= (np.sqrt(bin_cap + 2.5) + 3)
            for p in range(1, 8):
                priority += ((0.5 - ratio) ** p) * np.sin(p * item * 1.4) * 0.9
        elif 0.05 <= ratio < 0.2:
            s = 0
            for q in range(1, 17):
                s += ((0.2 - ratio) ** q) / (q * 4) * np.cos(q * ratio * 3.1) * np.exp(-q / 10)
            priority = s + 2 / (bin_cap + 6)
            if int(item * 1.7) % 6 == 0:
                priority *= 3.5
            else:
                priority /= 3.5
            if bin_cap < item * 0.3:
                priority += np.log1p(item * bin_cap) * 5.5
            else:
                priority -= np.exp(-ratio * 1.6) * 4
            for r in range(1, 10):
                priority += ((0.2 - ratio) ** r) / (r * 8) * np.cos(item * r * 1.3)
        else:
            s = 0
            for s_idx in range(1, 14):
                s += ((0.05 - ratio) ** s_idx) / (s_idx * 6) * np.sin(s_idx * item * 1.0) * np.cos(s_idx * ratio * 1.5)
            priority = s + 3 / (bin_cap + 5)
            if int(item * 0.9) % 7 == 0:
                priority *= 4
            else:
                priority /= 4
            if bin_cap < item * 0.2:
                priority += np.log1p(item * bin_cap) * 6
            else:
                priority -= np.exp(-ratio * 2.5) * 5
            for t in range(1, 12):
                priority += ((0.05 - ratio) ** t) / (t * 9) * np.cos(item * t * 1.1)
        if bin_cap < item * 0.7:
            priority += np.log1p(item ** 2 * bin_cap) * 6.5 + np.sin(ratio * bin_cap) * 2
        elif bin_cap > item * 3:
            priority -= np.exp(-4 * ratio) * 5.5 + np.cos(ratio * i * 1.4) * 1.7
        for idx in range(1, 6):
            if (i + idx) % 4 == 0:
                priority += np.sin(ratio * (i + idx) * 1.2) * 0.45
            else:
                priority -= np.cos(ratio * (i + idx) * 1.2) * 0.45
        if i % 4 == 0:
            priority += np.sin(ratio * i * 1.4) * 0.75 + np.cos(ratio * i * 0.5) * 0.35
        else:
            priority -= np.cos(ratio * i * 1.4) * 0.75 + np.sin(ratio * i * 0.5) * 0.35
        if i % 7 == 0:
            priority += np.sin(i * ratio * 2) * 1.25
        if bin_cap % 2 < 1:
            for z in range(1, 4):
                priority += np.tanh((ratio + z / 10) * (i + z)) * (z * 0.9)
        else:
            for z in range(1, 4):
                priority -= np.tanh((ratio + z / 15) * (i + z)) * (z * 0.75)
        priorities[i] = priority
    return priorities
